import json
import logging
from google.cloud import storage, firestore, pubsub_v1
from google.cloud.exceptions import NotFound
from typing import Dict, Any

def process_file_and_publish(event: Dict[str, Any], context):
    """Google Cloud Function to process Cloud Storage file, write to Firestore, and publish to Pub/Sub."""
    
    # Validate input
    if not event.get('bucket') or not event.get('name'):
        logging.error("Invalid event data")
        return
    
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Securely process file
    try:
        # Initialize clients
        storage_client = storage.Client()
        firestore_client = firestore.Client()
        pubsub_client = pubsub_v1.PublisherClient()
        
        # Get bucket and blob
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Download file content
        file_content = blob.download_as_text()
        
        # Process content (example: parse JSON)
        try:
            data = json.loads(file_content)
        except json.JSONDecodeError:
            logging.error("Invalid JSON in file")
            return
        
        # Write to Firestore
        collection_ref = firestore_client.collection('processed_files')
        doc_ref = collection_ref.document(file_name)
        doc_ref.set({
            'filename': file_name,
            'bucket': bucket_name,
            'data': data,
            'processed_at': firestore.SERVER_TIMESTAMP
        })
        
        # Publish to Pub/Sub
        topic_path = pubsub_client.topic_path('your-project-id', 'your-topic-name')
        message_data = {
            'filename': file_name,
            'bucket': bucket_name,
            'status': 'processed'
        }
        
        pubsub_client.publish(
            topic=topic_path,
            data=json.dumps(message_data).encode('utf-8')
        )
        
        logging.info(f"Successfully processed {file_name}")
        
    except NotFound:
        logging.error(f"File {file_name} not found")
    except Exception as e:
        logging.error(f"Error processing file {file_name}: {str(e)}")
        raise